/// <summary>
/// controller class for report proforma sales invoice
/// </summary>
class ETGSalesInvoiceProformaController extends SrsReportRunController
{
    SalesAgreementHeader salesAgreementHeader;
    ETGSalesInvoiceProformaReportContract   contract;
}

Method.Source:
public static ETGSalesInvoiceProformaController construct()
{
    return new EtgSalesInvoiceProformaController();
}

/// <summary>
/// entry point for running the report
/// </summary>
/// <param name = "_args">Args _args</param>
public static void main(Args _args)
{
    ETGSalesInvoiceProformaController controller = new ETGSalesInvoiceProformaController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGSalesInvoiceProformaReport, ETGReport));
    controller.parmShowDialog(false);
    controller.parmDialogCaption("@ETG_New:ProformaSalesInvoiceReport");
    controller.startOperation();
}

/// <summary>
/// modify contract for custom design
/// </summary>
protected void preRunModifyContract()
{
    str reportnameLocal;
    contract = this.parmReportContract().parmRdpContract();
    this.getReportContract().parmReportCaption("@ETG_New:ProformaSalesInvoiceReport");

    switch (args.record().TableId)
    {
        case  tableNum(SalesAgreementHeader):
            salesAgreementHeader =  args.record();
            contract.parmSalesAgreementId(salesAgreementHeader.SalesNumberSequence);
            reportnameLocal = ssrsReportStr(ETGSalesInvoiceProformaReport, ETGReport);
            break;
        default:
            throw error(Error::wrongUseOfFunction(funcName()));
    }
    this.parmReportName(reportnameLocal);
    this.parmReportContract().parmReportName(this.parmReportName());
}
